import React from "react";
import TaskItem from "TaskItem";

function TaskList({ tasks, deleteTask }) {
    return (
        <div>
            {tasks.map((task) => (
                <TaskItem key={task.id} task={task} deleteTask={deleteTask} />
            ))}
        </div>
    );
}

export default TaskList;
